const ontologyText = $json.ontology_text || '';

//
// ======================================================
// EXTRAER ONTOLOGY TYPE
// ======================================================
//

const ontologyTypeMatch = ontologyText.match(
  /OntologyType:\s*([A-Za-z0-9_-]+)/i
);

const ontologyType = ontologyTypeMatch
  ? ontologyTypeMatch[1].trim().toLowerCase()
  : 'unknown';

//
// ======================================================
// NORMALIZACIÓN
// ======================================================
//

const normalized = ontologyText
  .replace(/\r\n/g, '\n')
  .trim();

//
// ======================================================
// DIVIDIR POR CONCEPTOS (## concept)
// ======================================================
//

const rawSections = normalized.split(/^##\s+/gm);

const concepts = [];

for (const section of rawSections) {

  let block = section.trim();

  if (!block) {
    continue;
  }

  const lines = block.split('\n');

  const conceptId = (lines[0] || '').trim();

  //
  // Ignorar cabeceras generales
  //
  if (
    !conceptId ||
    conceptId.startsWith('#') ||
    conceptId.includes('OntologyType:')
  ) {
    continue;
  }

  //
  // ======================================================
  // LIMPIEZA DEL BLOQUE
  // ======================================================
  //
  block = block

    // eliminar separadores markdown
    .replace(/---+/g, '')

    // eliminar líneas decorativas tipo:
    // # ============================
    .replace(/^#\s*=+.*$/gm, '')

    // eliminar cabeceras de sección tipo:
    // # RISK CONCEPTS
    // # INSURANCE CONCEPTS
    .replace(/^#\s+[A-Z ]+$/gm, '')

    // compactar saltos de línea excesivos
    .replace(/\n{3,}/g, '\n\n')

    .trim();

  //
  // Recalcular identificador tras limpieza
  //
  const cleanedLines = block.split('\n');

  const cleanedConceptId =
    (cleanedLines[0] || '').trim();

  if (!cleanedConceptId) {
    continue;
  }

  //
  // Estadísticas
  //
  const wordCount = block
    .split(/\s+/)
    .filter(Boolean)
    .length;

  concepts.push({
    json: {

      // identificador único del concepto
      concept_id: cleanedConceptId,

      // ramo
      ontology_type: ontologyType,

      // texto para embedding
      ontology_text: block,

      // métricas
      concept_words: wordCount,
      concept_length: block.length

    }
  });
}

//
// ======================================================
// ORDEN CONSISTENTE
// ======================================================
//

concepts.sort((a, b) =>
  a.json.concept_id.localeCompare(
    b.json.concept_id
  )
);

return concepts;

const splitter = $('Ontology Splitter').item.json;

const conceptId = splitter.concept_id;
const ontologyType = splitter.ontology_type;
const ontologyText = splitter.ontology_text;

const embedding = $json.embedding;

function deterministicId(str) {
  let hash = 0;

  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }

  return Math.abs(hash);
}

const conceptKey = `${ontologyType}:${conceptId}`;
const pointId = deterministicId(conceptKey);

return {
  json: {
    points: [
      {
        id: pointId,
        vector: embedding,
        payload: {
          concept_key: conceptKey,
          concept_id: conceptId,
          ontology_type: ontologyType,
          ontology_text: ontologyText,
          searchable_text: ontologyText,
          concept_words: splitter.concept_words,
          concept_length: splitter.concept_length
        }
      }
    ]
  }
};
